pageContent:
.resumen-container {
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 80vh;
  padding: 20px;
}

.glass-card {
  width: 100%;
  max-width: 600px;
  background: rgba(20, 20, 20, 0.85);
  backdrop-filter: blur(15px);
  border: 1px solid rgba(255, 255, 255, 0.1);
  border-radius: 24px;
}

.item-row {
  background: rgba(255, 255, 255, 0.03);
  border-radius: 16px;
  transition: all 0.3s ease;
  border: 1px solid transparent;
}

.item-row:hover {
  background: rgba(255, 255, 255, 0.06);
  border-color: rgba(255, 193, 7, 0.2);
  transform: translateX(5px);
}

.qty-selector {
  background: rgba(0, 0, 0, 0.3);
  padding: 4px;
  border-radius: 12px;
  border: 1px solid rgba(255, 255, 255, 0.1);
}

.btn-qty {
  width: 32px;
  height: 32px;
  border: none;
  background: rgba(255, 255, 255, 0.1);
  color: white;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: all 0.2s;
}

.btn-qty:hover {
  background: #ffc107;
  color: black;
}

.qty-text {
  min-width: 30px;
  text-align: center;
  color: white;
  font-weight: bold;
}

.btn-remove {
  background: transparent;
  border: none;
  color: #ff4d4d;
  font-size: 1.2rem;
  opacity: 0.6;
  transition: 0.2s;
}

.btn-remove:hover {
  opacity: 1;
  transform: scale(1.1);
}

.btn-confirm {
  background: linear-gradient(135deg, #28a745 0%, #1e7e34 100%);
  color: white;
  border: none;
  border-radius: 16px;
  box-shadow: 0 4px 15px rgba(40, 167, 69, 0.3);
  transition: all 0.3s;
}

.btn-confirm:hover {
  transform: translateY(-2px);
  box-shadow: 0 6px 20px rgba(40, 167, 69, 0.5);
  color: white;
}

.btn-cancel {
  background: rgba(220, 53, 69, 0.1);
  border: 1px solid rgba(220, 53, 69, 0.3);
  color: #dc3545;
  border-radius: 12px;
  padding: 10px;
  transition: all 0.3s;
}

.btn-cancel:hover {
  background: #dc3545;
  color: white;
}

.x-small {
  font-size: 0.75rem;
}

.scroll-custom {
  max-height: 400px;
  overflow-y: auto;
  padding-right: 5px;
}

.scroll-custom::-webkit-scrollbar {
  width: 6px;
}

.scroll-custom::-webkit-scrollbar-thumb {
  background: rgba(255, 193, 7, 0.3);
  border-radius: 10px;
}
